mapper.select:
SELECT
    id, line_no, scene_name, field, scene_no, is_valid, create_at, update_at
FROM scene


        line_no = #{param.lineNo}


        AND scene_name like CONCAT(#{param.sceneName}, '%')


        AND field like CONCAT(#{param.field}, '%')


        AND scene_no = #{param.sceneNo}


        AND is_valid = #{param.isValid}

    AND is_delete = 0

LIMIT #{start}, #{limit}

SELECT
    COUNT(*)
FROM scene


        line_no = #{param.lineNo}


        AND scene_name like CONCAT(#{param.sceneName}, '%')


        AND field like CONCAT(#{param.field}, '%')


        AND scene_no = #{param.sceneNo}


        AND is_valid = #{param.isValid}

    AND is_delete = 0
